using UnityEngine;
using Cinemachine;

public class CinemachineExample : MonoBehaviour
{
    public CinemachineVirtualCamera virtualCamera;
    public CinemachineBrain cinemachineBrain;

    public float followSpeed = 5f;
    public float cameraDistance = 10f;
    public float cameraHeight = 5f;

    void Start()
    {
        // Get Cinemachine components
        if (virtualCamera == null)
        {
            virtualCamera = GetComponent<CinemachineVirtualCamera>();
            if (virtualCamera == null)
            {
                // Create a virtual camera
                GameObject camObj = new GameObject("CM vcam1");
                virtualCamera = camObj.AddComponent<CinemachineVirtualCamera>();
                // Set up basics
                virtualCamera.m_Lens.FieldOfView = 60f;
            }
        }

        // Get CinemachineBrain (on the camera)
        if (cinemachineBrain == null)
        {
            cinemachineBrain = Camera.main.GetComponent<CinemachineBrain>();
        }

        Debug.Log("Cinemachine initialized!");
    }

    void Update()
    {
        // Example: Switch cameras with keys
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            SetFollowTarget(Camera.main.transform);
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            SetLookAtTarget(Camera.main.transform);
        }

        // Example: Camera controls
        if (Input.GetKey(KeyCode.Q))
        {
            RotateCamera(-1f);
        }
        if (Input.GetKey(KeyCode.E))
        {
            RotateCamera(1f);
        }

        if (Input.GetKey(KeyCode.Z))
        {
            ZoomCamera(-1f);
        }
        if (Input.GetKey(KeyCode.X))
        {
            ZoomCamera(1f);
        }
    }

    public void SetFollowTarget(Transform target)
    {
        if (virtualCamera != null)
        {
            virtualCamera.Follow = target;
            Debug.Log("Follow target set to: " + target.name);
        }
    }

    public void SetLookAtTarget(Transform target)
    {
        if (virtualCamera != null)
        {
            virtualCamera.LookAt = target;
            Debug.Log("LookAt target set to: " + target.name);
        }
    }

    public void SetCameraPosition(Vector3 position)
    {
        if (virtualCamera != null)
        {
            Transform camTransform = virtualCamera.transform;
            camTransform.position = position;
        }
    }

    public void SetCameraRotation(Vector3 rotation)
    {
        if (virtualCamera != null)
        {
            Transform camTransform = virtualCamera.transform;
            camTransform.rotation = Quaternion.Euler(rotation);
        }
    }

    public void SetFieldOfView(float fov)
    {
        if (virtualCamera != null)
        {
            virtualCamera.m_Lens.FieldOfView = Mathf.Clamp(fov, 10f, 120f);
        }
    }

    public void RotateCamera(float direction)
    {
        if (virtualCamera != null)
        {
            Transform camTransform = virtualCamera.transform;
            camTransform.Rotate(Vector3.up, direction * 45f * Time.deltaTime);
        }
    }

    public void ZoomCamera(float direction)
    {
        if (virtualCamera != null)
        {
            float fov = virtualCamera.m_Lens.FieldOfView;
            fov += direction * 10f * Time.deltaTime;
            SetFieldOfView(fov);
        }
    }

    // Example: Shake the camera
    public void ShakeCamera(float amplitude, float frequency, float duration)
    {
        if (virtualCamera != null)
        {
            CinemachineBasicMultiChannelPerlin noise = virtualCamera.GetCinemachineComponent<CinemachineBasicMultiChannelPerlin>();

            if (noise == null)
            {
                noise = virtualCamera.AddCinemachineComponent<CinemachineBasicMultiChannelPerlin>();
            }

            noise.m_AmplitudeGain = amplitude;
            noise.m_FrequencyGain = frequency;

            // Reset after duration
            Invoke(nameof(StopShake), duration);
        }
    }

    public void StopShake()
    {
        if (virtualCamera != null)
        {
            CinemachineBasicMultiChannelPerlin noise = virtualCamera.GetCinemachineComponent<CinemachineBasicMultiChannelPerlin>();
            if (noise != null)
            {
                noise.m_AmplitudeGain = 0f;
                noise.m_FrequencyGain = 0f;
            }
        }
    }
}

